echo "Starting emoji replacement across HTML files..."

# Process each HTML file
for file in index.html new-zealand.html pricing.html community.html resources.html reports.html about.html contact.html; do
  if [ -f "$file" ]; then
    echo "Processing $file..."
    
    # Create backup
    cp "$file" "$file.bak"
    
    # Replace each emoji
    for emoji in "${!ICONS[@]}"; do
      svg="${ICONS[$emoji]}"
      # Escape special characters for sed
      escaped_svg=$(echo "$svg" | sed 's/[&/\]/\\&/g')
      sed -i '' "s|$emoji|$escaped_svg|g" "$file"
    done
    
    echo "✓ Completed $file"
  fi
done

echo "All files processed!"
echo "Backups saved with .bak extension"
